// client/src/pages/TasksPage.js
import React, { useEffect } from 'react';
import { useUser } from '../context/UserContext';
import ResourceBar from '../components/ResourceBar';
import Loading from '../components/Loading';
import { FishingIcon, HuntingIcon, CompassIcon } from '../components/Icons';
import axios from 'axios';

const TasksPage = () => {
  const { user, loading } = useUser();
  const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:3001/api';

  // Проверка и обновление ежедневных заданий
  useEffect(() => {
    const checkDailyTasks = async () => {
      if (!user) return;

      try {
        // Проверяем, нужно ли обновить задания
        const now = new Date();
        const lastReset = new Date(user.dailyTasks.lastReset);
        const daysPassed = Math.floor((now - lastReset) / (1000 * 60 * 60 * 24));

        if (daysPassed >= 1) {
          // Обновляем ежедневные задания
          await axios.post(`${API_URL}/game/tasks/${user.id}/reset`);
        }
      } catch (error) {
        console.error('Ошибка при обновлении ежедневных заданий:', error);
      }
    };

    checkDailyTasks();
  }, [user, API_URL]);

  if (loading || !user) {
    return <Loading />;
  }

  // Получение иконки для задания
  const getTaskIcon = (taskId) => {
    switch (taskId) {
      case 'fishing': return <FishingIcon className="w-5 h-5 text-blue-500" />;
      case 'hunting': return <HuntingIcon className="w-5 h-5 text-green-500" />;
      case 'exploring': return <CompassIcon className="w-5 h-5 text-purple-500" />;
      default: return null;
    }
  };

  // Получение названия задания
  const getTaskName = (taskId) => {
    switch (taskId) {
      case 'fishing': return 'Рыбалка';
      case 'hunting': return 'Охота';
      case 'exploring': return 'Исследование';
      default: return 'Задание';
    }
  };

  // Получение описания задания
  const getTaskDescription = (taskId) => {
    switch (taskId) {
      case 'fishing': return 'Наловить рыбы с любой кошкой';
      case 'hunting': return 'Собрать клубки шерсти с любой кошкой';
      case 'exploring': return 'Исследовать местность с любой кошкой';
      default: return 'Выполнить задание';
    }
  };

  return (
    <div className="pb-16">
      <ResourceBar />

      <div className="pt-16 px-4">
        <h1 className="text-2xl font-bold mb-4">Ежедневные задания</h1>

        {/* Список заданий */}
        {user.dailyTasks.tasks.map(task => (
          <div key={task.taskId} className="bg-white rounded-lg shadow-md p-4 mb-4">
            <div className="flex items-start">
              <div className="w-10 h-10 bg-gray-100 rounded-full flex items-center justify-center mr-3">
                {getTaskIcon(task.taskId)}
              </div>
              <div className="flex-grow">
                <h3 className="font-bold">{getTaskName(task.taskId)}</h3>
                <p className="text-sm text-gray-600">{getTaskDescription(task.taskId)}</p>

                {/* Прогресс задания */}
                <div className="mt-2">
                  <div className="flex justify-between text-xs mb-1">
                    <span>Прогресс:</span>
                    <span>{task.progress}%</span>
                  </div>
                  <div className="bg-gray-200 h-2 rounded-full w-full">
                    <div
                      className={`h-2 rounded-full ${task.completed ? 'bg-green-500' : 'bg-cat-primary'}`}
                      style={{ width: `${task.progress}%` }}
                    ></div>
                  </div>
                </div>

                {/* Статус задания */}
                {task.completed ? (
                  <div className="mt-2 text-sm text-green-600 font-medium">
                    Выполнено ✓
                  </div>
                ) : (
                  <div className="mt-2 text-sm text-gray-600">
                    Награда: 50 рыбы, 10 клубков шерсти
                  </div>
                )}
              </div>
            </div>
          </div>
        ))}

        {/* Информация о сбросе заданий */}
        <div className="bg-gray-50 rounded-lg p-4 text-center text-sm text-gray-600">
          <p>Ежедневные задания обновляются каждый день в полночь.</p>
        </div>
      </div>
    </div>
  );
};

export default TasksPage;
